def integerReplacement(n: int) -> int:
    if n == 1:
        return 0
    elif n == 2:
        return 1
    elif n % 2 == 0:
        return 2 + integerReplacement(n // 2)
    else:
        return 2 + min(integerReplacement(n + 1), integerReplacement(n - 1))

